# ---------------- Malumotlar bazasi ----------------
def db():
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row
    return conn

def init_db():
    conn = db(); c = conn.cursor()
    c.execute("""CREATE TABLE IF NOT EXISTS users(
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        username TEXT UNIQUE NOT NULL,
        pw_hash TEXT NOT NULL,
        role TEXT NOT NULL DEFAULT 'viewer',
        full_name TEXT DEFAULT '')""")
    c.execute("""CREATE TABLE IF NOT EXISTS kv(
        key TEXT PRIMARY KEY, value TEXT)""")
    conn.commit()

    sk = get_kv(c, "secret_key")
    if not sk:
        sk = os.environ.get("SECRET_KEY") or secrets.token_hex(32)
        set_kv(c, "secret_key", sk); conn.commit()
    app.secret_key = os.environ.get("SECRET_KEY") or sk

    c.execute("SELECT COUNT(*) AS n FROM users")
    if c.fetchone()["n"] == 0:
        c.execute("INSERT INTO users(username, pw_hash, role, full_name) VALUES(?,?,?,?)",
                  ("admin", generate_password_hash("admin123"), "admin", "Bosh administrator"))
        conn.commit()

    # Malumotni tayyorlash / migratsiya
    need_seed = False
    raw = get_kv(c, "state")
    if not raw:
        need_seed = True
    else:
        try:
            st = json.loads(raw)
            if int(st.get("data_version", 0)) < DATA_VERSION or "periods" not in st:
                need_seed = True
        except Exception:
            need_seed = True
    if need_seed:
        set_kv(c, "state", json.dumps(SEED_STATE, ensure_ascii=False)); conn.commit()
    conn.close()

def get_kv(c, k):
    c.execute("SELECT value FROM kv WHERE key=?", (k,))
    r = c.fetchone()
    return r["value"] if r else None

def set_kv(c, k, v):
    c.execute("INSERT INTO kv(key,value) VALUES(?,?) ON CONFLICT(key) DO UPDATE SET value=excluded.value", (k, v))

def load_state(c):
    st = json.loads(get_kv(c, "state"))
    st.setdefault("data_version", DATA_VERSION)
    st.setdefault("settings", {"tax": 12, "inps": 0.1, "union": 1, "bhm": 412000})
    st.setdefault("lists", {"pos": [], "deg": ["-"], "dept": []})
    st.setdefault("periods", {})
    return st

# ---------------- Auth yordamchilari ----------------
def current_user():
    uid = session.get("uid")
    if not uid: return None
    conn = db(); c = conn.cursor()
    c.execute("SELECT id, username, role, full_name FROM users WHERE id=?", (uid,))
    r = c.fetchone(); conn.close()
    return dict(r) if r else None

def login_required(f):
    @wraps(f)
    def w(*a, **k):
        if not session.get("uid"): return redirect(url_for("login"))
        return f(*a, **k)
    return w

def role_required(*roles):
    def deco(f):
        @wraps(f)
        def w(*a, **k):
            u = current_user()
            if not u: return redirect(url_for("login"))
            if u["role"] not in roles: abort(403)
            return f(*a, **k)
        return w
    return deco

# ---------------- Marshrutlar ----------------
@app.route("/login", methods=["GET", "POST"])
def login():
    if request.method == "POST":
        un = request.form.get("username", "").strip()
        pw = request.form.get("password", "")
        conn = db(); c = conn.cursor()
        c.execute("SELECT * FROM users WHERE username=?", (un,))
        r = c.fetchone(); conn.close()
        if r and check_password_hash(r["pw_hash"], pw):
            session["uid"] = r["id"]
            return redirect(url_for("index"))
        flash("Login yoki parol notogri.")
    if session.get("uid"): return redirect(url_for("index"))
    return render_template("login.html")

@app.route("/logout")
def logout():
    session.clear()
    return redirect(url_for("login"))

@app.route("/change-password", methods=["POST"])
@login_required
def change_password():
    u = current_user()
    old = request.form.get("old",""); new = request.form.get("new","")
    conn = db(); c = conn.cursor()
    c.execute("SELECT pw_hash FROM users WHERE id=?", (u["id"],))
    r = c.fetchone()
    if not check_password_hash(r["pw_hash"], old):
        conn.close(); flash("Joriy parol notogri."); return redirect(url_for("users_page") if u["role"]=="admin" else url_for("index"))
    if len(new) < 5:
        conn.close(); flash("Yangi parol kamida 5 belgidan iborat bolsin."); return redirect(url_for("index"))
    c.execute("UPDATE users SET pw_hash=? WHERE id=?", (generate_password_hash(new), u["id"]))
    conn.commit(); conn.close(); flash("Parol ozgartirildi.")
    return redirect(url_for("index"))

@app.route("/")
@login_required
def index():
    u = current_user()
    conn = db(); c = conn.cursor()
    state = load_state(c); conn.close()
    return render_template("app.html", state=json.dumps(state, ensure_ascii=False), user=u)

# ----- API: davr (oy) malumotini saqlash -----
@app.route("/api/state", methods=["POST"])
@role_required("admin", "editor")
def api_state():
    payload = request.get_json(force=True)
    conn = db(); c = conn.cursor()
    st = load_state(c)
    period = payload.get("period")
    if period:
        st["periods"][period] = {
            "norm": payload.get("norm", 22),
            "nextId": payload.get("nextId", 1),
            "employees": payload.get("employees", {"teachers": [], "admin": [], "tech": []}),
        }
    if "lists" in payload and payload["lists"]:
        st["lists"] = payload["lists"]
    set_kv(c, "state", json.dumps(st, ensure_ascii=False))
    conn.commit(); conn.close()
    return jsonify(ok=True)

@app.route("/api/settings", methods=["POST"])
@role_required("admin")
def api_settings():
    payload = request.get_json(force=True)
    conn = db(); c = conn.cursor()
    st = load_state(c)
    st["settings"] = payload
    set_kv(c, "state", json.dumps(st, ensure_ascii=False))
    conn.commit(); conn.close()
    return jsonify(ok=True)

# ----- Foydalanuvchilarni boshqarish (admin) -----
@app.route("/users")
@role_required("admin")
def users_page():
    conn = db(); c = conn.cursor()
    c.execute("SELECT id, username, role, full_name FROM users ORDER BY id")
    users = [dict(r) for r in c.fetchall()]; conn.close()
    return render_template("users.html", users=users, user=current_user())

@app.route("/users/add", methods=["POST"])
@role_required("admin")
def users_add():
    un = request.form.get("username","").strip()
    pw = request.form.get("password","")
    role = request.form.get("role","viewer")
    fn = request.form.get("full_name","").strip()
    if role not in ("admin","editor","viewer"): role = "viewer"
    if not un or len(pw) < 5:
        flash("Login kiriting va parol kamida 5 belgidan iborat bolsin.")
        return redirect(url_for("users_page"))
    conn = db(); c = conn.cursor()
    try:
        c.execute("INSERT INTO users(username, pw_hash, role, full_name) VALUES(?,?,?,?)",
                  (un, generate_password_hash(pw), role, fn))
        conn.commit(); flash(f"'{un}' foydalanuvchisi qoshildi.")
    except sqlite3.IntegrityError:
        flash("Bu login band. Boshqa login tanlang.")
    conn.close()
    return redirect(url_for("users_page"))

@app.route("/users/update", methods=["POST"])
@role_required("admin")
def users_update():
    uid = int(request.form.get("id"))
    role = request.form.get("role")
    newpw = request.form.get("password","")
    me = current_user()
    conn = db(); c = conn.cursor()
    if role in ("admin","editor","viewer"):
        if uid == me["id"] and role != "admin":
            c.execute("SELECT COUNT(*) AS n FROM users WHERE role='admin'")
            if c.fetchone()["n"] <= 1:
                conn.close(); flash("Yagona adminni pasaytirib bolmaydi."); return redirect(url_for("users_page"))
        c.execute("UPDATE users SET role=? WHERE id=?", (role, uid))
    if newpw:
        if len(newpw) < 5:
            conn.close(); flash("Parol kamida 5 belgidan iborat bolsin."); return redirect(url_for("users_page"))
        c.execute("UPDATE users SET pw_hash=? WHERE id=?", (generate_password_hash(newpw), uid))
    conn.commit(); conn.close(); flash("Saqlandi.")
    return redirect(url_for("users_page"))

@app.route("/users/delete", methods=["POST"])
@role_required("admin")
def users_delete():
    uid = int(request.form.get("id"))
    me = current_user()
    if uid == me["id"]:
        flash("Ozingizni ochira olmaysiz."); return redirect(url_for("users_page"))
    conn = db(); c = conn.cursor()
    c.execute("DELETE FROM users WHERE id=?", (uid,))
    conn.commit(); conn.close(); flash("Foydalanuvchi ochirildi.")
    return redirect(url_for("users_page"))

@app.errorhandler(403)
def forbidden(e):
    return render_template("403.html"), 403

with app.app_context():
    init_db()

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", 5000)), debug=False)
